// Bad names
int d;                          // elapsed time?
List<int[]> theList;            // list of what?
boolean flag;                   // flag for what?
void process(List<int[]> l) {}  // process how?

// Good names
int elapsedDays;
List<Cell> gameBoard;
boolean isActive;
void calculateMonthlySales(List<Order> orders) {}

// Don't encode the type
String nameString;   // just: name
List userList;       // just: users
int[] intArray;      // just: scores

// Don't make readers decode
void send(String m, String r);  // m=message? r=recipient?
void sendEmail(String message, String recipientEmail); // clear

// Too many responsibilities
public Order checkout(Cart cart, boolean sendEmail, boolean isGuest) {
    Order order = createOrder(cart);
    if (isGuest) createGuestAccount(cart);
    payment.charge(order);
    inventory.reserve(order);
    if (sendEmail) notifier.sendConfirmation(order);
    return order;
}

// After: focused functions, no flag params
public Order placeOrder(Cart cart) {
    Order order = createOrder(cart);
    payment.charge(order);
    inventory.reserve(order);
    return order;
}

public void notifyCustomer(Order order) {
    notifier.sendConfirmation(order);
}

// Flag param anti-pattern — split into two methods
void render(boolean isSuite) {}  // bad
void renderSingle() {}           // good
void renderSuite() {}            // good

// Bad: restates the code
i++;  // increment i

