// Newspaper metaphor: high-level entry point first
public class OrderProcessor {

    // Public API at the top (high-level)
    public Order process(Cart cart) {
        Order order = buildOrder(cart);
        applyDiscounts(order);
        persist(order);
        return order;
    }

    // Private helpers below (details)
    private Order buildOrder(Cart cart) { ... }
    private void applyDiscounts(Order order) { ... }
    private void persist(Order order) { ... }
}

// Vertical openness: blank lines between concepts
class UserService {
    private final UserRepository repo;
    private final Notifier notifier;

    public User register(UserRequest req) {
        validate(req);
        User user = createUser(req);
        repo.save(user);

        notifier.sendWelcome(user); // blank line: different concept starts
        return user;
    }
}

// Bad: return code forces caller to check every time
int result = repository.save(user); // -1 means error?
if (result == -1) { handleError(); }

// Good: exceptions for exceptional conditions
repository.save(user); // throws DataAccessException on failure

// Never swallow exceptions
try {
    process();
} catch (Exception e) {
    // BAD: swallowed — failure is invisible
}

// Wrap third-party exceptions
public User findById(long id) {
    try {
        return repository.findById(id); // throws HibernateException
    } catch (HibernateException e) {
        throw new UserNotFoundException("User " + id + " not found", e);
        // callers don't need to know about Hibernate
    }
}

// Avoid null returns
public Optional<User> findByEmail(String email) {
    return Optional.ofNullable(db.findByEmail(email));
